66	func WithConsumerEnvelopeTranslator() protostrate.ConsumerOption {
67		return protostrate.WithConsumerEnvelopeTranslator(func(b []byte) (*message.Envelope, error) {
68			var env contracts.Envelope
69			err := proto.Unmarshal(b, &env)
70			if err != nil {
71				return nil, fmt.Errorf("failed to unmarshal telecom contract: %w", err)
72			}
73	
74			response := &message.Envelope{
75				CreatedAt:     env.GetCreatedAt(),
76				Payload:       env.GetPayload(),
77				ReplayTargets: env.GetReplayTargets(),
78				AppliesAt:     env.GetAppliesAt(),
79			}
80	
81			if env.GetCorrelationToken() != nil {
82				response.CorrelationToken = env.GetCorrelationToken().GetValue()
83			}
84	
85			if env.GetId() != nil {
86				response.Id = env.GetId().GetValue()
87			}
88	
89			if env.GetSender() != nil {
90				response.Sender = &message.Sender{
91					App:       env.GetSender().GetApp(),
92					Namespace: env.GetSender().GetNamespace(),
93				}
94			}
95	
96			if env.GetOpentracing() != nil {
97				response.Opentracing = &message.Opentracing{
98					Metadata: env.GetOpentracing().GetMetadata(),
99				}
100			}
101	
102			if env.GetAudit() != nil {
103				response.Audit = &message.Audit{
104					Subject:      env.GetAudit().GetSubject(),
105					RequestedBy:  env.GetAudit().GetRequestedBy(),
106					AuthorisedBy: env.GetAudit().GetAuthorisedBy(),
107					Channel:      env.GetAudit().GetChannel(),
108				}
109			}
110	
111			return response, nil
112		})
113	}
