41	func WithWaitableHttpServer(ctx context.Context, httpServer *http.Server, serverName string) func() error {
42		return func() error {
43			errCh := make(chan error)
44	
45			go func() {
46				err := StartHttpServer(ctx, httpServer, serverName)
47				if err != nil {
48					errCh <- err
49				}
50			}()
51	
52			select {
53			case <-ctx.Done():
54				tlog.WithAttribute("serverName", serverName).
55					Info(ctx, "gracefully stopping http server")
56				return httpServer.Close()
57			case err := <-errCh:
58				tlog.WithError(err).
59					WithAttribute("serverName", serverName).
60					Error(ctx, "http server shutdown")
61				return err
62			}
63		}
64	}
